import React from "react";
import { useState } from "react";
import "./nav.css";

export default function Nav() {
  const [Active, IsActive] = useState("off");
  const [Style, setStyle] = useState("pushMenu2");

  const handleClick = () => {
    if (Active === "off") {
      IsActive("true");
      setStyle("pushMenu");
    } else {
      IsActive("off");
      setStyle("pushMenu2");
    }
  };

  return (
    <div>
      <div className={Style}>
        <div className="containerSocial">
          <div className="social">
            <img className="imgSocial" src="" />
            <p>GitHub</p>
          </div>
          <div className="social">
            <img className="imgSocial" src="" />
            <p>LinkedIn</p>
          </div>
          <div className="social">
            <img
              className="imgSocial"
              src="https://assets.stickpng.com/images/580b57fcd9996e24bc43c53e.png"
            />
            <p>Twitter</p>
          </div>
          <div className="social">
            <img className="imgSocial" src="" />
            <p>Instagram</p>
          </div>
        </div>
      </div>

      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}

